#include <stdio.h>
#include <stdlib.h>

int* findDish(int N, int K, long long L) {
    int* dish = (int*) malloc(N * sizeof(int));
    L--;
    for (int i = N - 1; i >= 0; i--) {
        dish[i] = L % K + 1;
        L /= K;
    }
    return dish;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, K;
        long long L;
        scanf("%d %d %lld", &N, &K, &L);
        int* dish = findDish(N, K, L);
        for (int i = 0; i < N; i++) {
            printf("%d ", dish[i]);
        }
        printf("\n");
        free(dish);
    }
    return 0;
}

