code.Java:
import java.util.Scanner;
public class Main {
    public static int[] findDish(int N, int K, long L) {
        int[] dish = new int[N];
        L--;
        for (int i = N - 1; i >= 0; i--) {
            dish[i] = (int) (L % K + 1);
            L /= K;
        }
        return dish;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            long L = scanner.nextLong();
            int[] dish = findDish(N, K, L);
            for (int i = 0; i < N; i++) {
                System.out.print(dish[i] + " ");
            }
            System.out.println();
        }
    }
}

